from pathlib import Path

root = Path(r"C:\Users\Gebruiker\Rezzerv_Github")
pre = root / "backend/app/receipt_ingestion/preprocessing/receipt_image_preprocessing.py"
req = root / "backend/requirements.txt"

pre.write_text('from __future__ import annotations\n\nfrom dataclasses import asdict, dataclass, field\nfrom io import BytesIO\nimport os\nfrom pathlib import Path\nfrom typing import Any\n\nfrom PIL import Image, ImageOps\n\ntry:\n    import cv2\n    import numpy as np\nexcept Exception:\n    cv2 = None\n    np = None\n\ntry:\n    from rembg import remove as rembg_remove\nexcept Exception:\n    rembg_remove = None\n\n\nIMAGE_SUFFIXES = {".jpg", ".jpeg", ".png", ".webp", ".bmp"}\nALPHA_THRESHOLD = 12\nMIN_ALPHA_COVERAGE = 0.015\nMAX_ALPHA_COVERAGE = 0.90\nMIN_CONTOUR_AREA_RATIO = 0.01\n\n\n@dataclass\nclass ReceiptImagePreprocessingDecision:\n    preprocessing_step: str\n    selected_route: str\n    applied_steps: list[str]\n    fallback_reason: list[str]\n    perspective_normalization: dict[str, Any] | None\n    diagnostics: dict[str, Any] = field(default_factory=dict)\n\n    def to_dict(self) -> dict[str, Any]:\n        return asdict(self)\n\n\ndef _debug_dir() -> Path | None:\n    value = os.environ.get("REZZERV_RECEIPT_PREPROCESS_DEBUG_DIR")\n    if not value:\n        return None\n    path = Path(value)\n    path.mkdir(parents=True, exist_ok=True)\n    return path\n\n\ndef _save_debug(name: str, image: Image.Image, diagnostics: dict[str, Any]) -> None:\n    out = _debug_dir()\n    if out is None:\n        return\n    path = out / name\n    image.save(path)\n    diagnostics.setdefault("debug_files", []).append(str(path))\n\n\ndef _encode_png(image: Image.Image) -> bytes:\n    buf = BytesIO()\n    image.save(buf, format="PNG")\n    return buf.getvalue()\n\n\ndef _order_points(points):\n    rect = np.zeros((4, 2), dtype="float32")\n    s = points.sum(axis=1)\n    rect[0] = points[np.argmin(s)]\n    rect[2] = points[np.argmax(s)]\n    diff = np.diff(points, axis=1)\n    rect[1] = points[np.argmin(diff)]\n    rect[3] = points[np.argmax(diff)]\n    return rect\n\n\ndef _warp_rgba(rgba_arr, quad):\n    rect = _order_points(quad.astype("float32"))\n    tl, tr, br, bl = rect\n\n    width_a = np.linalg.norm(br - bl)\n    width_b = np.linalg.norm(tr - tl)\n    max_width = int(max(width_a, width_b))\n\n    height_a = np.linalg.norm(tr - br)\n    height_b = np.linalg.norm(tl - bl)\n    max_height = int(max(height_a, height_b))\n\n    if max_width < 180 or max_height < 300:\n        return None, {"reject": "warped_size_too_small", "max_width": max_width, "max_height": max_height}\n\n    dst = np.array(\n        [[0, 0], [max_width - 1, 0], [max_width - 1, max_height - 1], [0, max_height - 1]],\n        dtype="float32",\n    )\n    matrix = cv2.getPerspectiveTransform(rect, dst)\n    warped = cv2.warpPerspective(rgba_arr, matrix, (max_width, max_height), borderMode=cv2.BORDER_CONSTANT, borderValue=(0, 0, 0, 0))\n\n    if warped.shape[1] > warped.shape[0]:\n        warped = cv2.rotate(warped, cv2.ROTATE_90_COUNTERCLOCKWISE)\n\n    return warped, {"quad": rect.astype(float).round(2).tolist(), "output_size": [int(warped.shape[1]), int(warped.shape[0])]}\n\n\ndef _find_receipt_quad_from_alpha(alpha, diagnostics: dict[str, Any]):\n    mask = (alpha > ALPHA_THRESHOLD).astype("uint8") * 255\n    total = int(mask.shape[0] * mask.shape[1])\n    foreground = int(np.count_nonzero(mask))\n    coverage = float(foreground / total) if total else 0.0\n\n    diagnostics["alpha_mask"] = {\n        "foreground_pixels": foreground,\n        "total_pixels": total,\n        "coverage": coverage,\n        "threshold": ALPHA_THRESHOLD,\n    }\n\n    _save_debug("10_alpha_mask.png", Image.fromarray(mask), diagnostics)\n\n    if coverage < MIN_ALPHA_COVERAGE:\n        return None, "alpha_coverage_too_low"\n    if coverage > MAX_ALPHA_COVERAGE:\n        return None, "alpha_coverage_too_high"\n\n    # Work on alpha only. Close small gaps in the receipt, never use white composite.\n    close_kernel = np.ones((31, 31), np.uint8)\n    open_kernel = np.ones((7, 7), np.uint8)\n    closed = cv2.morphologyEx(mask, cv2.MORPH_CLOSE, close_kernel, iterations=2)\n    closed = cv2.morphologyEx(closed, cv2.MORPH_OPEN, open_kernel, iterations=1)\n    _save_debug("11_alpha_mask_closed.png", Image.fromarray(closed), diagnostics)\n\n    contours, _ = cv2.findContours(closed, cv2.RETR_EXTERNAL, cv2.CHAIN_APPROX_SIMPLE)\n    diagnostics["alpha_contours_found"] = len(contours)\n    if not contours:\n        return None, "no_alpha_contour"\n\n    contour = max(contours, key=cv2.contourArea)\n    area = float(cv2.contourArea(contour))\n    area_ratio = area / float(total) if total else 0.0\n    diagnostics["largest_alpha_contour"] = {"area": area, "area_ratio": area_ratio}\n\n    if area_ratio < MIN_CONTOUR_AREA_RATIO:\n        return None, "largest_alpha_contour_too_small"\n\n    contour_img = np.zeros_like(closed)\n    cv2.drawContours(contour_img, [contour], -1, 255, 8)\n    _save_debug("12_largest_alpha_contour.png", Image.fromarray(contour_img), diagnostics)\n\n    perimeter = cv2.arcLength(contour, True)\n    quad = None\n\n    for epsilon in (0.008, 0.01, 0.015, 0.02, 0.03, 0.04, 0.06):\n        approx = cv2.approxPolyDP(contour, epsilon * perimeter, True)\n        if len(approx) == 4:\n            quad = approx.reshape(4, 2).astype("float32")\n            diagnostics["quad_detection"] = {"method": "approxPolyDP_on_alpha", "epsilon": epsilon}\n            break\n\n    if quad is None:\n        rect = cv2.minAreaRect(contour)\n        quad = cv2.boxPoints(rect).astype("float32")\n        diagnostics["quad_detection"] = {"method": "minAreaRect_on_alpha_fallback"}\n\n    overlay = np.zeros((alpha.shape[0], alpha.shape[1], 3), dtype=np.uint8)\n    cv2.drawContours(overlay, [contour], -1, (80, 80, 80), 6)\n    cv2.drawContours(overlay, [quad.astype("int32")], -1, (255, 255, 255), 10)\n    _save_debug("20_quad_overlay.png", Image.fromarray(overlay), diagnostics)\n\n    return quad, None\n\n\ndef _composite_rgba_on_white(rgba_arr) -> Image.Image:\n    rgba = Image.fromarray(rgba_arr.astype("uint8"), "RGBA")\n    white = Image.new("RGBA", rgba.size, (255, 255, 255, 255))\n    return Image.alpha_composite(white, rgba).convert("RGB")\n\n\ndef _safe_neutralized(rgba: Image.Image, diagnostics: dict[str, Any], reason: str, perspective: dict[str, Any] | None = None) -> tuple[bytes, ReceiptImagePreprocessingDecision]:\n    white = Image.new("RGBA", rgba.size, (255, 255, 255, 255))\n    neutralized = Image.alpha_composite(white, rgba).convert("RGB")\n    _save_debug("40_final_runtime_preprocessed.png", neutralized, diagnostics)\n    diagnostics["final_size"] = [neutralized.width, neutralized.height]\n    return _encode_png(neutralized), ReceiptImagePreprocessingDecision(\n        "receipt_image_preprocessing",\n        "R9-25B_geometry_failed_rembg_neutralized",\n        ["rembg_remove_background", "white_background_composite"],\n        [reason],\n        perspective,\n        diagnostics,\n    )\n\n\ndef apply_receipt_image_preprocessing(file_bytes: bytes, filename: str) -> tuple[bytes, ReceiptImagePreprocessingDecision]:\n    """R9-25B: geometry on rembg alpha only.\n\n    Important: no geometry decisions are made on the white composite background.\n    The receipt shape is derived from non-transparent pixels in rembg\'s alpha channel.\n    """\n    diagnostics: dict[str, Any] = {"filename": filename}\n    suffix = Path(filename or "").suffix.lower()\n\n    if suffix and suffix not in IMAGE_SUFFIXES:\n        return file_bytes, ReceiptImagePreprocessingDecision(\n            "receipt_image_preprocessing",\n            "original",\n            [],\n            ["unsupported_image_suffix"],\n            None,\n            diagnostics,\n        )\n\n    if rembg_remove is None:\n        return file_bytes, ReceiptImagePreprocessingDecision(\n            "receipt_image_preprocessing",\n            "original",\n            [],\n            ["rembg_unavailable"],\n            None,\n            diagnostics,\n        )\n\n    if cv2 is None or np is None:\n        return file_bytes, ReceiptImagePreprocessingDecision(\n            "receipt_image_preprocessing",\n            "original",\n            [],\n            ["cv2_or_numpy_unavailable"],\n            None,\n            diagnostics,\n        )\n\n    try:\n        original = Image.open(BytesIO(file_bytes))\n        original = ImageOps.exif_transpose(original).convert("RGB")\n        _save_debug("00_input_original.png", original, diagnostics)\n\n        rgba_bytes = rembg_remove(file_bytes)\n        rgba = Image.open(BytesIO(rgba_bytes)).convert("RGBA")\n        rgba = ImageOps.exif_transpose(rgba)\n        _save_debug("09_rembg_raw_rgba.png", rgba, diagnostics)\n    except Exception as exc:\n        return file_bytes, ReceiptImagePreprocessingDecision(\n            "receipt_image_preprocessing",\n            "original",\n            [],\n            [f"rembg_or_decode_failed:{type(exc).__name__}"],\n            None,\n            diagnostics,\n        )\n\n    alpha = np.array(rgba.getchannel("A"))\n    quad, reason = _find_receipt_quad_from_alpha(alpha, diagnostics)\n    if quad is None:\n        return _safe_neutralized(rgba, diagnostics, reason or "quad_not_found")\n\n    rgba_arr = np.array(rgba)\n    warped_rgba, perspective = _warp_rgba(rgba_arr, quad)\n    if warped_rgba is None:\n        return _safe_neutralized(rgba, diagnostics, "warp_failed", perspective)\n\n    warped_preview = _composite_rgba_on_white(warped_rgba)\n    _save_debug("30_perspective_warp.png", warped_preview, diagnostics)\n\n    w, h = warped_preview.size\n    max_side = max(w, h)\n    if max_side > 3200:\n        scale = 3200 / float(max_side)\n        warped_preview = warped_preview.resize((int(w * scale), int(h * scale)), Image.Resampling.LANCZOS)\n        diagnostics["resize_after_warp"] = {"from": [w, h], "to": [warped_preview.width, warped_preview.height]}\n\n    _save_debug("40_vertical_normalized.png", warped_preview, diagnostics)\n\n    gray = ImageOps.grayscale(warped_preview)\n    _save_debug("50_final_ocr_input.png", gray, diagnostics)\n\n    # Hard safeguard against the R9-25A failure mode.\n    arr = np.array(warped_preview.convert("L"))\n    near_white_ratio = float(np.mean(arr > 248))\n    diagnostics["final_near_white_ratio"] = near_white_ratio\n    if near_white_ratio > 0.985:\n        return _safe_neutralized(rgba, diagnostics, "final_output_nearly_all_white", perspective)\n\n    _save_debug("40_final_runtime_preprocessed.png", warped_preview, diagnostics)\n    diagnostics["final_size"] = [warped_preview.width, warped_preview.height]\n\n    return _encode_png(warped_preview), ReceiptImagePreprocessingDecision(\n        "receipt_image_preprocessing",\n        "R9-25B_rembg_alpha_geometry_normalized",\n        ["rembg_remove_background", "alpha_mask_largest_contour", "alpha_quad_detection", "rgba_perspective_warp", "white_background_composite"],\n        [],\n        perspective,\n        diagnostics,\n    )\n', encoding="utf-8")

requirements = req.read_text(encoding="utf-8")
requirements = requirements.replace("rembg>=2.0,<3\n", "")
if "rembg[cpu]>=2.0,<3" not in requirements:
    if not requirements.endswith("\n"):
        requirements += "\n"
    requirements += "rembg[cpu]>=2.0,<3\n"
req.write_text(requirements, encoding="utf-8")

